1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Trivial / empty cases ---
6	  it("empty item list quote -> premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Base premiums for main items (with implicit first-insurance and fee) ---
15	  // For a brand-new customer (0 years, no prior contract): premium = base + 10% first-insurance + 5 G fee
16	  it.todo("single sword for new customer -> 100 base + 10 first + 5 fee = 115 G");
17	  it.todo("single amulet for new customer -> 60 base + 6 first + 5 fee = 71 G");
18	  it.todo("single staff for new customer -> 80 base + 8 first + 5 fee = 93 G");
19	  it.todo("single potion for new customer -> 40 base + 4 first + 5 fee = 49 G");
20	
21	  // --- Component pricing & block-of-3 rule ---
22	  it.todo("2 runes -> 50 G base premium (no block)");
23	  it.todo("3 runes -> 60 G base premium (block applies)");
24	  it.todo("4 runes -> 100 G base premium (no block: requires exactly 3)");
25	  it.todo("7 runes -> 175 G base premium (no full block partition)");
26	  it.todo("2 runes + 1 moonstone -> 75 G base premium (no block, different types)");
27	  it.todo("3 runes + 3 moonstones -> 120 G base premium (two separate blocks)");
28	
29	  // --- Modifier scope on multi-item policies ---
30	  it.todo("cursed sword + plain amulet -> base 160, +50 curse = 210 before policy modifiers/fee");
31	
32	  // --- Modifier thresholds ---
33	  it.todo("customer with exactly 2 years -> loyalty discount applies");
34	  it.todo("sword with exactly enchantment 5 -> high-enchantment surcharge applies");
35	  it.todo("cursed sword with enchantment 5 -> both curse and high-enchantment surcharges apply");
36	  it.todo("sword with enchantment 4 (not cursed) -> no surcharges");
37	
38	  // --- Rounding ---
39	  it.todo("premium yielding 197.5 G -> rounded UP to 198 G (in MHPCO's favor)");
40	  it.todo("payout yielding 350.5 G -> rounded DOWN to 350 G (in MHPCO's favor)");
41	
42	  // --- Integration examples ---
43	  it.todo("newcomer with cursed sword (steel, ench 3) -> premium 165 G");
44	  it.todo("long-standing customer's second contract: cursed sword (steel, ench 7), 3 years -> 160 G");
45	
46	  // --- Claim: standard reimbursement ---
47	  it.todo("regular sword (steel, ench 3), damage 500 G -> payout 400 G (500 - 100 deductible)");
48	  it.todo("damage to a rune (value 250), damage 200 -> payout 100 G (200 - 100)");
49	
50	  // --- Claim: enchantment & dragon material clauses ---
51	  it.todo("dragon-material sword, ench 8, damage 1000 -> payout 400 G (50% then deductible)");
52	  it.todo("dragon-material sword, ench 9, damage 1000 -> payout 400 G (50% wins, then deductible)");
53	  it.todo("dragon-material sword, ench 5, damage 800 -> payout 700 G (dragon full, then deductible)");
54	  it.todo("steel sword, ench 9, damage 1000 -> payout 400 G (50% then deductible)");
55	
56	  // --- Claim: deductible per damage event ---
57	  it.todo("dragon attack damages sword (500) and amulet (300) -> payout 600 G (100 deductible per item)");
58	
59	  // --- Claim: cap ---
60	  it.todo("policy covers sword + amulet -> insurance sum 1600, cap 3200 G");
61	  it.todo("cursed sword -> cap 2000 G (based on unmodified insurance value)");
62	  it.todo("policy covers sword + 3 runes (block) -> insurance sum 1750 G");
63	  it.todo("sword cap 2000, claim 1500 -> payout 1400, remaining cap 600");
64	  it.todo("second claim of 1500 -> payout 600 (capped), remaining cap 0");
65	
66	  // --- Multiple items of the same type ---
67	  it.todo("policy covers two swords -> insurance sum 2000 G, cap 4000 G");
68	  it.todo("two swords, two damage entries -> each gets its own deductible");
69	  it.todo("damages has more entries of a type than policy covers -> CLI exits non-zero");
70	
71	  // --- Error cases ---
72	  it.todo("quote with unknown item type -> CLI exits non-zero, error on stderr, no results");
73	  it.todo("claim references item not in policy -> CLI exits non-zero, error on stderr");
74	  it.todo("claim damage with negative amount -> CLI exits non-zero, error on stderr");
75	});
